sys_script_include.script:
var ApplicationPropertyService = Class.create();
ApplicationPropertyService.prototype = {
  initialize: function () {
    this.logger = new Logger('ApplicationPropertyService');
  },

  get: function(name) {
	var propName = Constants.APP_SCOPE + '.' + name;
	return gs.getProperty(propName);
  },

  set: function(name, value) {
	var propName = Constants.APP_SCOPE + '.' + name;
	var gr = new GlideRecord("sys_properties");
	gr.addQuery("name", propName);
	gr.query();

	if (gr.next()) {
		var prevValue = this.get(name);
		this.logger.debug("Setting property '{0}' value: {1} -> {2}", propName, prevValue, value);
		gr.value = value;
		gr.update();
		this.logger.info("Set property '{0}' value: {1} -> {2}", propName, prevValue, value);
	} else {
		this.logger.error("Failed to set property. Property: {0}, not found!", propName);
	}
  },

  getEnvironmentUrls: function () {
    this.logger.debug(
      'getEnvironmentUrls(): Getting environments. Production mode: {0}',
      gs.getProperty(Constants.APP_SCOPE + '.production_mode')
    );

    var environments = JSON.parse(gs.getProperty(Constants.APP_SCOPE + '.environments'));
    var isProduction = gs.getProperty(Constants.APP_SCOPE + '.production_mode') === 'true';

    return environments.filter(function (environment) {
      return environment.name === (isProduction ? 'production' : 'test');
    })[0];
  },

  setBaseApiUrl: function (baseApiUrl) {
	var propName = 'base_api_url';
	var baseApiUrlPropName = Constants.APP_SCOPE + '.' + propName;

    var environments = this.getEnvironmentUrls();
    var checkUrl = function (_ref) {
      return baseApiUrl === _ref.url;
    };

    this.set(propName, baseApiUrl);

  },

  type: 'ApplicationPropertyService',
};
